    saveBreakdown() {
      var _this = this;
      return _asyncToGenerator(function* () {
        document.body.classList.add('ctc-saving');
        _this.downloadingBreakdownPdf = true;
        try {
          const employeeId = _this.employeeId || _this.resolveEmployeeId();
          if (!employeeId) {
            _this.feedback.error('Employee id is missing. Unable to generate the salary revision PDF.');
            return;
          }
          const response = yield _this.apiService.getemployeectcdetails(employeeId).toPromise();
          const ctcDetails = _this.normalizeEmployeeCtcDetailResponse(response);
          if (!ctcDetails) {
            _this.feedback.error('Employee CTC details were not available for PDF generation.');
            return;
          }
          _this.employeeCtcDetails = ctcDetails;
          _this.salaryRevisionLetterData = _this.buildSalaryRevisionLetterData(ctcDetails);
          yield _this.waitForLetterRender();
          if (!_this.salaryRevisionPdfHost?.nativeElement) {
            _this.feedback.error('Unable to prepare the salary revision letter for download.');
            return;
          }
          yield _this.salaryRevisionLetterPdfService.downloadPagesAsPdf(_this.salaryRevisionPdfHost.nativeElement, _this.buildSalaryRevisionFileName(ctcDetails));
          _this.feedback.success('Salary revision PDF download started.');
        } catch (error) {
          console.error('Salary revision PDF download failed:', error);
          _this.feedback.error('Failed to generate the salary revision PDF. Please try again.');
        } finally {
          _this.downloadingBreakdownPdf = false;
          document.body.classList.remove('ctc-saving');
        }
      })();
    }
