    normalizeEmployeeCtcDetailResponse(response) {
      const source = Array.isArray(response) ? response : Array.isArray(response?.data) ? response.data : Array.isArray(response?.result) ? response.result : response ? [response] : [];
      return source.find(item => Number(item?.year || 0) === Number(this.selectedYear || 0)) || source[source.length - 1] || null;
