    buildSalaryRevisionLetterData(ctcDetails) {
      const employeeName = `${this.employeeProfile?.employee_name || this.employeeProfile?.employeeName || this.tokenStorage.getEmpname() || ''}`.trim() || 'Employee';
      const empCode = `${this.employeeProfile?.employee_code || this.employeeProfile?.emp_code || this.employeeProfile?.empid || ctcDetails?.empid || ''}`.trim() || `${ctcDetails?.empid || this.employeeId || ''}`.trim();
      const department = `${this.employeeProfile?.department || this.employeeProfile?.department_name || this.employeeProfile?.departmentName || ''}`.trim() || 'Department';
      const designation = `${this.employeeProfile?.designation || this.employeeProfile?.designation_name || this.employeeProfile?.designationName || ''}`.trim() || 'Designation';
      const effectiveFrom = ctcDetails?.updated_date || ctcDetails?.created_date || new Date();
      const selectedYear = Number(ctcDetails?.year || this.selectedYear || this.currentYear) || this.currentYear;
      return {
        employeeName,
        empCode,
        department,
        designation,
        effectiveFrom,
        letterDate: new Date(),
        financialYear: this.formatFinancialYear(selectedYear),
